<template>
    <view>
        <!-- 自定义顶部导航 -->
        <u-navbar :title="info.name" :placeholder="true" :safeAreaInsetTop="true" :autoBack="true">
            <view class="u-nav-slot" slot="right">
                <text @click="toCsv" class="tc">詳細</text>
            </view>
        </u-navbar>
        <view class="containe">
            <view class="userInfo">
                <view class="infoItem">
                    <view class="itemname">
                        会員ID
                    </view>
                    <view class="itemValue" v-text="info.member_id"></view>
                </view>
                <view class="infoItem">
                    <view class="itemname">
                        顧客NO
                    </view>
                    <view class="itemValue" v-text="info.member_no"></view>
                </view>
            </view>

            <view class="cardInfo">
                <view class="cardTitle">
                    {{info.card_shop_name}}({{info.card_name}})
                </view>
                <view class="cardY">
                    <view class="cardInner">
                        <view class="seal" @click="showModal" v-for="(item,index) in list" :key="index">
                            <text v-text="index + 1"></text>
                            <view class="sealed" v-if="item.sealed">
                                <image :src="item.seal_icon" :style="`transform: translate(-10000px);filter: drop-shadow(10000px 0 0 ${item.seal_color});`" mode=""></image>
                                <view class="sealTime" v-text="item.time"></view>
                            </view>
                        </view>
                    </view>
                </view>
                <view class="cardInfos">
                    <view class="ciItem">
                        <view class="ciLeft">
                            有効期限
                        </view>
                        <view class="ciRight" v-text="info.expire_time"></view>
                    </view>
                    <view class="ciItem">
                        <view class="ciLeft">
                            備　考
                        </view>
                        <view class="ciRight" v-text="cardInfo.remark"></view>
                    </view>
                </view>
            </view>
            <view class="appoint">
                <view class="appointTitle">
                    予 約
                </view>
                <view class="appointItem" v-for="(item,index) in info.orders">
                    <view class="aItem">
                        <view class="aItemImage">
                            <image src="../../../../static/icons/record1.png" mode=""></image>
                        </view>
                        <view class="aTime">
                            <view class="time">
                                {{item.date}}({{item.week}})　{{item.start}}〜{{item.end}}
                            </view>
                            <view class="copy" v-text="item.menu_name"></view>
                        </view>
                    </view>
                    <view class="aItem">
                        <view class="aItemImage">
                            <image src="../../../../static/icons/record3.png" mode=""></image>
                        </view>
                        <view class="aUser">
                            長谷川杏
                        </view>
                    </view>
                </view>
               
            </view>
            <view class="special">
                <view class="specialTitle">
                    特 典
                </view>
                <u-swiper :list="cardInfo.discount_images" height="250" @click="click" :indicator="true" indicatorMode="dot" indicatorActiveColor="#000000" indicatorInactiveColor="rgba(0,0,0,.3)"></u-swiper>
                <view class="remark">
                    当店で取り扱いのワックスorトリートメントのどちらかをプレゼントいたします。
                </view>
            </view>
        </view>
        <!-- 添加印章 -->
        <u-popup :show="show" mode="bottom" @close="close">
            <view class="popContent">
                <view class="popTitle">
                    スタンプ付与数
                </view>
                <view class="choosecount">
                    <view class="reduce" @click="reduce">
                      <image src="../../../../static/icons/reduce.png" mode=""></image>  
                    </view>
                    <view class="coiunt" v-text="number"></view>
                    <view class="plus" @click="plus">
                        <image src="../../../../static/icons/plus.png" mode=""></image>  
                    </view>
                </view>
                <u-button @click="save" class="btn" text="決　定"></u-button>
            </view>
        </u-popup> 
    </view>
</template>

<script>
    import {
        getMemberDetail,
        addPoints
    } from "@/api/index.js"
    export default {
        data() {
            return {
                title: "name",
                number:3,
                banner: [],
                show:false,
                query:{},
                info:{},
                list: [],
                cardInfo:{}
            }
        },
        created() {
          console.log("created")
        },
        onLoad(options) {
          let that = this
          console.log("options",options)
          let query = options
          that.query = query
          that.getDetail(query.id)  
        },
        methods: {
            showModal(){
                let that = this
                that.show = true
                console.log(123)
            },
            click(){
                
            },
            toCsv(){
                uni.redirectTo({
                    url:"../../detail/detail?id="+this.info.id
                }) 
            },
            
            formatDate(ms) {
                const date = new Date(ms)
                const Y = date.getFullYear()
                const M = date.getMonth() + 1 < 10 ? '0' + (date.getMonth() + 1) : date.getMonth() + 1
                const D = date.getDate()
                return `${Y}-${M}-${D}`
            },
            
            close(){
                this.show = false
            },
            
            reduce(){
              if(this.number > 1){
                  this.number -= 1
              }  
            },
            
            plus(){
               if(this.number < this.info.card.count){
                   this.number += 1
               }  
            },
            
            save(){
              let that = this
              let data = {}
              data.plus = that.number
              data.mid = that.info.id
              addPoints(data).then((res) => {
                 
                  if(res.code == 200){
                      uni.showToast({
                          title:res.message
                      })
                      that.getDetail(that.info.id)
                  }else{
                      uni.showToast({
                          title:res.message,
                          icon:"none"
                      })
                  }
              })
            },
            
            getDetail(id){
                let that = this
                let data = {}
                data.id = id
                getMemberDetail(data).then((res) => {
                    if(res.code == 200){
                        that.info = res.data
                        that.cardInfo = res.data.card
                        console.log('userinfo',that.info.card.discount_images)
                        let tem = []
                        let obj = {}
                        obj["sealed"] = false
                        obj["time"] = ""
                        obj["sealImage"] = ""
                        console.log(res.data.card.count - res.data.seals.length)
                        for(let i = 0; i < res.data.card.count - res.data.seals.length; i++){
                            tem.push(obj)
                        }
                        console.log("temp",tem)
                        that.info.seals.forEach((val,index) => {
                            val.sealed = true
                            val.time = that.formatDate(val.time*1000)
                        })
                        that.list = [...that.info.seals , ...tem]
                    }
                })
            }
        }
    }
</script>

